def binary_search(xs, target):
    lo, hi = 0, len(xs)         # half-open: [lo, hi)
    while lo < hi:
        mid = (lo + hi) // 2
        if xs[mid] == target:
            return mid
        if xs[mid] < target:
            lo = mid + 1
        else:
            hi = mid             # NOTE: not mid - 1, because hi is exclusive
    return -1

print(binary_search([1, 3, 5, 7, 9, 11, 13, 15, 17], 13))   # 6
print(binary_search([1, 3, 5, 7, 9, 11, 13, 15, 17], 8))    # -1

def smallest_k_satisfying(predicate, lo, hi):
    '''Find the smallest k in [lo, hi] for which predicate(k) is True.
    Assumes the predicate is monotonic: once True it stays True.'''
    while lo < hi:
        mid = (lo + hi) // 2
        if predicate(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo if predicate(lo) else None

